// MARK: - Bridge Message Model

struct BridgeMessage {
    let action: String
    let payload: [String: Any]
    let callbackId: String?
    
    init?(from body: Any) {
        guard let dict = body as? [String: Any],
              let action = dict["action"] as? String else {
            return nil
        }
        
        self.action = action
        self.payload = dict["payload"] as? [String: Any] ?? [:]
        self.callbackId = dict["callbackId"] as? String
    }
    
    var isValid: Bool {
        return WebViewConfiguration.allowedActions.contains(action)
            && callbackId?.count ?? 0 <= 64
            && callbackId?.range(of: "^[a-zA-Z0-9_-]+$", options: .regularExpression) != nil || callbackId == nil
    }
}

// MARK: - Bridge Response

struct BridgeResponse {
    let callbackId: String?
    let success: Bool
    let data: [String: Any]?
    let error: String?
    
    func toJavaScript() -> String? {
        guard let callbackId = callbackId else { return nil }
        
        let sanitizedCallbackId = callbackId.replacingOccurrences(of: "'", with: "")
            .replacingOccurrences(of: "\"", with: "")
            .replacingOccurrences(of: "\\", with: "")
            .replacingOccurrences(of: "\n", with: "")
            .replacingOccurrences(of: "\r", with: "")
        
