            return nil
        }
        
        var responseDict: [String: Any] = [
            "success": success,
            "callbackId": sanitizedCallbackId
        ]
        
        if let data = data {
            responseDict["data"] = data
        }
        if let error = error {
            responseDict["error"] = error
        }
        
        guard let jsonData = try? JSONSerialization.data(withJSONObject: responseDict),
              let jsonString = String(data: jsonData, encoding: .utf8) else {
            return nil
        }
        
        return "window.__nativeBridgeCallback('\(sanitizedCallbackId)', \(jsonString));"
    }
}

// MARK: - Origin Validator

final class OriginValidator {
    
    static func isAllowedOrigin(_ url: URL?) -> Bool {
        guard let url = url,
              let scheme = url.scheme?.lowercased(),
              let host = url.host?.lowercased() else {
            return false
        }
        
        guard WebViewConfiguration.allowedSchemes.contains(scheme) else {
            return false
        }
        
        return WebViewConfiguration.allowedOrigins.contains(host)
    }
    
    static func isAllowedNavigation(_ url: URL?) -> Bool {
        guard let url = url else { return false }
        
        if url.scheme == "about" && url.absoluteString == "about:blank" {
            return true
        }
        
        return isAllowedOrigin(url)
    }
}

// MARK: - Rate Limiter

final class RateLimiter {
    private var timestamps: [String: [Date]] = [:]
    private let maxRequests: Int
    private let windowSeconds: TimeInterval
    private let queue = DispatchQueue(label: "com.app.ratelimiter")
    
    init(maxRequests: Int = 10, windowSeconds: TimeInterval = 60) {
        self.maxRequests = maxRequests
        self.windowSeconds = windowSeconds
    }
    
    func shouldAllow(action: String) -> Bool {
        return queue.sync {
            let now = Date()
            let cutoff = now.addingTimeInterval(-windowSeconds)
            
            var actionTimestamps = timestamps[action] ?? []
            actionTimestamps = actionTimestamps.filter { $0 > cutoff }
            
            if actionTimestamps.count >= maxRequests {
                return false
            }
            
            actionTimestamps.append(now)
            timestamps[action] = actionTimestamps
            return true
        }
    }
}

// MARK: - In-App Purchase Manager

final class IAPManager: NSObject, SKProductsRequestDelegate, SKPaymentTransactionObserver {
    
    static let shared = IAPManager()
    
    private var products: [String: SKProduct] = [:]
    private var purchaseCompletionHandlers: [String: (Bool, String?) -> Void] = [:]
    private let allowedProductIds: Set<String> = [
        "com.yourapp.premium.monthly",
        "com.yourapp.premium.yearly",
        "com.yourapp.credits.100"
    ]
    
    private override init() {
        super.init()
        SKPaymentQueue.default().add(self)
    }
    
    deinit {
        SKPaymentQueue.default().remove(self)
    }
    
    func fetchProducts() {
        let request = SKProductsRequest(productIdentifiers: allowedProductIds)
        request.delegate = self
        request.start()
    }
    
    func purchase(productId: String, completion: @escaping (Bool, String?) -> Void) {
        guard allowedProductIds.contains(productId) else {
            completion(false, "Invalid product identifier")
            return
        }
        
        guard SKPaymentQueue.canMakePayments() else {
            completion(false, "In-app purchases are disabled")
            return
        }
        
        guard let product = products[productId] else {
            completion(false, "Product not found. Please try again.")
            return
        }
        
        purchaseCompletionHandlers[productId] = completion
        let payment = SKPayment(product: product)
        SKPaymentQueue.default().add(payment)
    }
    
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        for product in response.products {
            products[product.productIdentifier] = product
        }
    }
    
    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for transaction in transactions {
            let productId = transaction.payment.productIdentifier
            
            switch transaction.transactionState {
            case .purchased:
                purchaseCompletionHandlers[productId]?(true, nil)
                purchaseCompletionHandlers.removeValue(forKey: productId)
                queue.finishTransaction(transaction)
                
            case .failed:
                let errorMessage = transaction.error?.localizedDescription ?? "Purchase failed"
                purchaseCompletionHandlers[productId]?(false, errorMessage)
                purchaseCompletionHandlers.removeValue(forKey: productId)
                queue.finishTransaction(transaction)
                
            case .restored:
                queue.finishTransaction(transaction)
                
            case .deferred, .purchasing:
                break
                
            @unknown default:
                break
            }
        }
    }
}

