    // MARK: - Native Action Handlers
    
    private func handleCameraAccess(message: BridgeMessage) {
        let status = AVCaptureDevice.authorizationStatus(for: .video)
        
        switch status {
        case .authorized:
            sendResponse(BridgeResponse(
                callbackId: message.callbackId,
                success: true,
                data: ["status": "authorized"],
                error: nil
            ))
            
        case .notDetermined:
            AVCaptureDevice.requestAccess(for: .video) { [weak self] granted in
                self?.sendResponse(BridgeResponse(
                    callbackId: message.callbackId,
                    success: granted,
                    data: ["status": granted ? "authorized" : "denied"],
                    error: granted ? nil : "Camera access denied by user"
                ))
            }
            
        case .denied, .restricted:
            sendResponse(BridgeResponse(
                callbackId: message.callbackId,
                success: false,
                data: ["status": "denied"],
                error: "Camera access denied. Please enable in Settings."
            ))
            
        @unknown default:
            sendResponse(BridgeResponse(
                callbackId: message.callbackId,
                success: false,
                data: nil,
                error: "Unknown camera authorization status"
            ))
        }
    }
    
    private func handlePushNotifications(message: BridgeMessage) {
        UNUserNotificationCenter.current().getNotificationSettings { [weak self] settings in
            switch settings.authorizationStatus {
            case .authorized, .provisional:
                DispatchQueue.main.async {
                    UIApplication.shared.registerForRemoteNotifications()
                }
                self?.sendResponse(BridgeResponse(
                    callbackId: message.callbackId,
                    success: true,
                    data: ["status": "authorized"],
                    error: nil
                ))
                
            case .notDetermined:
                UNUserNotificationCenter.current().requestAuthorization(
                    options: [.alert, .badge, .sound]
                ) { granted, error in
                    if granted {
                        DispatchQueue.main.async {
                            UIApplication.shared.registerForRemoteNotifications()
                        }
                    }
                    self?.sendResponse(BridgeResponse(
                        callbackId: message.callbackId,
                        success: granted,
                        data: ["status": granted ? "authorized" : "denied"],
                        error: error?.localizedDescription
                    ))
                }
                
            case .denied:
                self?.sendResponse(BridgeResponse(
                    callbackId: message.callbackId,
                    success: false,
                    data: ["status": "denied"],
                    error: "Push notifications denied. Please enable in Settings."
                ))
                
            case .ephemeral:
                self?.sendResponse(BridgeResponse(
                    callbackId: message.callbackId,
                    success: true,
                    data: ["status": "ephemeral"],
                    error: nil
                ))
                
            @unknown default:
                self?.sendResponse(BridgeResponse(
                    callbackId: message.callbackId,
                    success: false,
                    data: nil,
                    error: "Unknown notification authorization status"
                ))
            }
        }
    }
    
    private func handleInAppPurchase(message: BridgeMessage) {
        guard let productId = message.payload["productId"] as? String,
              !productId.isEmpty,
              productId.count <= 128,
              productId.range(of: "^[a-zA-Z0-9._]+$", options: .regularExpression) != nil else {
            sendResponse(BridgeResponse(
                callbackId: message.callbackId,
                success: false,
                data: nil,
                error: "Invalid product identifier"
            ))
            return
        }
        
        IAPManager.shared.purchase(productId: productId) { [weak self] success, error in
            self?.sendResponse(BridgeResponse(
                callbackId: message.callbackId,
                success: success,
                data: success ? ["productId": productId, "purchased": true] : nil,
                error: error
            ))
        }
    }
    
    private func handleGetDeviceInfo(message: BridgeMessage) {
        let device = UIDevice.current
        let info: [String: Any] = [
            "platform": "iOS",
            "systemVersion": device.systemVersion,
            "model": device.model,
            "appVersion": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "unknown",
            "buildNumber": Bundle.main.infoDictionary?["CFBundleVersion"] as? String ?? "unknown"
        ]
        
        sendResponse(BridgeResponse(
            callbackId: message.callbackId,
            success: true,
            data: info,
            error: nil
        ))
    }
    
    private func handleHapticFeedback(message: BridgeMessage) {
        let style = message.payload["style"] as? String ?? "medium"
        
        DispatchQueue.main.async { [weak self] in
            let allowedStyles = ["light", "medium", "heavy", "success", "warning", "error", "selection"]
            guard allowedStyles.contains(style) else {
                self?.sendResponse(BridgeResponse(
                    callbackId: message.callbackId,
                    success: false,
                    data: nil,
                    error: "Invalid haptic style"
                ))
                return
            }
            
            switch style {
            case "light":
                UIImpactFeedbackGenerator(style: .light).impactOccurred()
            case "medium":
                UIImpactFeedbackGenerator(style: .medium).impactOccurred()
            case "heavy":
                UIImpactFeedbackGenerator(style: .heavy).impactOccurred()
            case "success":
                UINotificationFeedbackGenerator().notificationOccurred(.success)
            case "warning":
                UINotificationFeedbackGenerator().notificationOccurred(.warning)
            case "error":
                UINotificationFeedbackGenerator().notificationOccurred(.error)
            case "selection":
                UISelectionFeedbackGenerator().selectionChanged()
            default:
                UIImpactFeedbackGenerator(style: .medium).impactOccurred()
            }
            
            self?.sendResponse(BridgeResponse(
                callbackId: message.callbackId,
                success: true,
                data: nil,
                error: nil
            ))
        }
    }
}

// MARK: - WKScriptMessageHandler

extension HybridWebViewController: WKScriptMessageHandler {
    
    func userContentController(
        _ userContentController: WKUserContentController,
        didReceive message: WKScriptMessage
    ) {
        guard message.name == WebViewConfiguration.bridgeHandlerName else {
            return
        }
        
        guard OriginValidator.isAllowedOrigin(message.frameInfo.request.url ?? webView.url) else {
            print("[Bridge] Rejected message from unauthorized origin: \(message.frameInfo.request.url?.absoluteString ?? "nil")")
            return
        }
        
        guard message.frameInfo.isMainFrame else {
            print("[Bridge] Rejected message from non-main frame")
            return
        }
        
        guard let body = message.body as? [String: Any],
              let jsonData = try? JSONSerialization.data(withJSONObject: body),
              jsonData.count <= WebViewConfiguration.maxMessageSizeBytes else {
            print("[Bridge] Message too large or invalid format")
            return
        }
        
        guard let bridgeMessage = BridgeMessage(from: message.body) else {
            print("[Bridge] Failed to parse bridge message")
            return
        }
        
        guard bridgeMessage.isValid else {
            print("[Bridge] Invalid or disallowed action: \(bridgeMessage.action)")
            sendResponse(BridgeResponse(
                callbackId: bridgeMessage.callbackId,
                success: false,
                data: nil,
                error: "Action not allowed"
            ))
            return
        }
        
        guard rateLimiter.shouldAllow(action: bridgeMessage.action) else {
            print("[Bridge] Rate limit exceeded for action: \(bridgeMessage.action)")
            sendResponse(BridgeResponse(
                callbackId: bridgeMessage.callbackId,
                success: false,
                data: nil,
                error: "Too many requests. Please try again later."
            ))
            return
        }
        
        switch bridgeMessage.action {
        case "requestCameraAccess":
            handleCameraAccess(message: bridgeMessage)
        case "requestPushNotifications":
            handlePushNotifications(message: bridgeMessage)
        case "initiateInAppPurchase":
            handleInAppPurchase(message: bridgeMessage)
        case "getDeviceInfo":
            handleGetDeviceInfo(message: bridgeMessage)
        case "hapticFeedback":
            handleHapticFeedback(message: bridgeMessage)
        default:
            sendResponse(BridgeResponse(
                callbackId: bridgeMessage.callbackId,
                success: false,
                data: nil,
                error: "Unknown action"
            ))
        }
    }
}

// MARK: - WKNavigationDelegate

extension HybridWebViewController: WKNavigationDelegate {
    
    func webView(
        _ webView: WKWebView,
        decidePolicyFor navigationAction: WKNavigationAction,
        decisionHandler: @escaping (WKNavigationActionPolicy) -> Void
    ) {
        guard let url = navigationAction.request.url else {
            decisionHandler(.cancel)
            return
        }
        
        if url.scheme == "tel" || url.scheme == "mailto" {
            if UIApplication.shared.canOpenURL(url) {
                UIApplication.shared.open(url)
            }
            decisionHandler(.cancel)
            return
        }
        
        if url.scheme == "itms-appss" || url.scheme == "itms-apps" {
            decisionHandler(.cancel)
            return
        }
        
        guard OriginValidator.isAllowedNavigation(url) else {
            print("[Navigation] Blocked navigation to: \(url.absoluteString)")
            
            if let scheme = url.scheme, WebViewConfiguration.allowedSchemes.contains(scheme.lowercased()) {
                presentExternalLinkAlert(url: url)
            }
            
            decisionHandler(.cancel)
            return
        }
        
        decisionHandler(.allow)
    }
    
    func webView(
        _ webView: WKWebView,
        decidePolicyFor navigationResponse: WKNavigationResponse,
        decisionHandler: @escaping (WKNavigationResponsePolicy) -> Void
    ) {
        guard let httpResponse = navigationResponse.response as? HTTPURLResponse else {
            decisionHandler(.allow)
            return
        }
        
        let statusCode = httpResponse.statusCode
        if statusCode >= 400 {
            print("[Navigation] HTTP error: \(statusCode)")
        }
        
        decisionHandler(.allow)
    }
    
    func webView(
        _ webView: WKWebView,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust,
              let host = webView.url?.host,
              WebViewConfiguration.allowedOrigins.contains(host) else {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        let credential = URLCredential(trust: serverTrust)
        completionHandler(.useCredential, credential)
    }
    
    func webView(_ webView: WKWebView, didFail navigation: WKNavigation!, withError error: Error) {
        handleWebViewError(error)
    }
    
    func webView(_ webView: WKWebView, didFailProvisionalNavigation navigation: WKNavigation!, withError error: Error) {
        handleWebViewError(error)
    }
    
    private func handleWebViewError(_ error: Error) {
        let nsError = error as NSError
        
        if nsError.domain == NSURLErrorDomain && nsError.code == NSURLErrorCancelled {
            return
