                }
                h1 { font-size: 24px; margin-bottom: 12px; }
                p { font-size: 16px; color: #6e6e73; line-height: 1.5; }
                button {
                    margin-top: 24px;
                    padding: 12px 32px;
                    font-size: 16px;
                    background: #007AFF;
                    color: white;
                    border: none;
                    border-radius: 12px;
                    cursor: pointer;
                    -webkit-tap-highlight-color: transparent;
                }
            </style>
        </head>
        <body>
            <div class="container">
                <h1>Connection Error</h1>
                <p>\(sanitizedMessage)</p>
                <button onclick="window.location.reload()">Try Again</button>
            </div>
        </body>
        </html>
        """
        
        webView.loadHTMLString(errorHTML, baseURL: nil)
    }
    
    private func presentExternalLinkAlert(url: URL) {
        let alert = UIAlertController(
            title: "Open External Link",
            message: "This link will open outside the app. Continue?",
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Open", style: .default) { _ in
            UIApplication.shared.open(url)
        })
        
        present(alert, animated: true)
    }
}

// MARK: - WKUIDelegate

extension HybridWebViewController: WKUIDelegate {
    
    func webView(
        _ webView: WKWebView,
        createWebViewWith configuration: WKWebViewConfiguration,
        for navigationAction: WKNavigationAction,
        windowFeatures: WKWindowFeatures
    ) -> WKWebView? {
        if let url = navigationAction.request.url, OriginValidator.isAllowedNavigation(url) {
            webView.load(navigationAction.request)
        }
        return nil
    }
    
    func webView(
        _ webView: WKWebView,
        runJavaScriptAlertPanelWithMessage message: String,
        initiatedByFrame frame: WKFrameInfo,
        completionHandler: @escaping () -> Void
    ) {
        guard OriginValidator.isAllowedOrigin(frame.request.url) else {
            completionHandler()
            return
        }
        
        let truncatedMessage = String(message.prefix(500))
        
        let alert = UIAlertController(title: nil, message: truncatedMessage, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler()
        })
        present(alert, animated: true)
    }
    
    func webView(
        _ webView: WKWebView,
        runJavaScriptConfirmPanelWithMessage message: String,
        initiatedByFrame frame: WKFrameInfo,
        completionHandler: @escaping (Bool) -> Void
    ) {
        guard OriginValidator.isAllowedOrigin(frame.request.url) else {
            completionHandler(false)
            return
        }
        
        let truncatedMessage = String(message.prefix(500))
        
        let alert = UIAlertController(title: nil, message: truncatedMessage, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(false)
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(true)
        })
        present(alert, animated: true)
    }
    
    func webView(
        _ webView: WKWebView,
        runJavaScriptTextInputPanelWithPrompt prompt: String,
        defaultText: String?,
        initiatedByFrame frame: WKFrameInfo,
        completionHandler: @escaping (String?) -> Void
    ) {
        guard OriginValidator.isAllowedOrigin(frame.request.url) else {
            completionHandler(nil)
            return
        }
        
        let truncatedPrompt = String(prompt.prefix(500))
        
        let alert = UIAlertController(title: nil, message: truncatedPrompt, preferredStyle: .alert)
        alert.addTextField { textField in
            textField.text = defaultText
        }
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(nil)
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(alert.textFields?.first?.text)
        })
        present(alert, animated: true)
    }
}

// MARK: - LeakAvoider (prevents retain cycle with WKUserContentController)

final class LeakAvoider: NSObject, WKScriptMessageHandler {
    
    weak var delegate: WKScriptMessageHandler?
    
    init(delegate: WKScriptMessageHandler) {
        self.delegate = delegate
        super.init()
    }
    
    func userContentController(
        _ userContentController: WKUserContentController,
        didReceive message: WKScriptMessage
    ) {
        delegate?.userContentController(userContentController, didReceive: message)
    }
}

